; Generated by linker
.import __MAIN_START__, __MAIN_SIZE__
.import __BSS_RUN__, __BSS_SIZE__

.include "macros.inc"
.include "basic.inc"

.zeropage

; A pointer to the current program line
line_ptr: .res 2

; A pointer to the start of the program
program_ptr: .res 2

; The start of the variable name table
variable_name_table_ptr: .res 2

; The start of the variable value table; maintained as the end of the variable name table
value_table_ptr: .res 2

; The start of the heap; reset to value_table_ptr plus the size of the value table when program is run
heap_ptr: .res 2

; The address of "high memory" that will not be touched by the interpreter
himem_ptr: .res 2

; The number of variables in the program
variable_count: .res 1

; Pointer to the variable value set by a statement like LET, INPUT, and READ
variable_value_ptr: .res 2

.bss

; The program line produced by the parser
line_buffer: .res 256

.code

; Initializes a new program.
; Inserts an empty zero-length line -1 into the program space.

initialize_program:

; This function makes assumptions about these offsets

.assert Line::next_line_offset = 0, error
.assert Line::number = 1, error

        mvax    #(__BSS_RUN__ + __BSS_SIZE__), program_ptr
        stax    line_ptr                    ; Set program_ptr and line_ptr to end of BSS
        ldy     #Line::number+1             ; Offset of line number high byte (should be 2)
        lda     #$FF                        ; Line number = -1
        sta     (line_ptr),y                ; Save line number high byte
        dey
        sta     (line_ptr),y                ; Line number low byte
        dey     
        lda     #Line::data                 ; This is the offset of the next line if this line has no data
        sta     (line_ptr),y                ; Save as next line offset
        jsr     add_line_ptr_offset         ; Adding A to line_ptr gives variable_name_table_ptr in AX
        stax    variable_name_table_ptr
        tay                                 ; Add 1 to variable_name_table_ptr for ending 0
        iny
        sty     value_table_ptr
        bne     @no_carry                   ; Low byte did not wrap around to 0
        inx                                 ; Increment high byte in X
@no_carry:
        stx     value_table_ptr+1           ; Save high byte
        lda     #0                          ; Load zero into A
        tay                                 ; Write index is also zero
        sta     (variable_name_table_ptr),y ; Initialize variable name table to 0
        sta     variable_count              ; Initialize number of variables to 0
        mvax    #(__MAIN_START__ + __MAIN_SIZE__), himem_ptr
        rts

; Sets line_ptr to program_ptr.
; Returns line_ptr in AX.
; Y SAFE, BC SAFE, DE SAFE

reset_line_ptr:
        mvax    program_ptr, line_ptr
        rts

; Searches for a line in the program.
; This function needs to be reasonably fast because it will be called every time the program executes GOTO, 
; GOSUB, RESTORE, or any other function that requires a line number.
; AX = the line number
; Carry clear if ok (the was found), carry set if error (line not found).
; Sets line_ptr, line_number, and line_length if the line was found.
; If not found, line_ptr is left set to where the line would have been, i.e., pointing
; to the next-higher line.

find_line:
        stax    DE
        jsr     reset_line_ptr          ; Set line_ptr to beginning of program
        jmp     @test_line              ; Skip over first advance_line_ptr call
@next_line:      
        jsr     advance_line_ptr        ; Advance to the next line    
@test_line:
        ldy     #Line::number+1         ; Index of high byte of line number (expected to be 2)
        lda     (line_ptr),y        
        cmp     E       
        bcc     @next_line              ; Line number high byte is <target; go to next line
        bne     @return                 ; Return with carry set
        dey                             ; High byte is equal; decrement Y to get low byte of line number
        lda     (line_ptr),y            ; Check the low byte of line number
        cmp     D                       ; Same logic for low byte
        bcc     @next_line     
        bne     @return                 ; If not the line then reutrn with carry bit set
        clc                             ; If it was the line then return with carry clear
@return:        
        rts     

; Advances the current line pointer to the next line. This is called from find_line so we don't set line_number
; or line_length or assume they've been set, because in find_line we want to scan the program as quickly as possible.
; line_ptr = current line (updated)
; Returns new line_ptr value in AX.
; BC SAFE, DE SAFE

advance_line_ptr:
        ldy     #0                      ; Need offset 2 to get length
        lda     (line_ptr),y            ; Get length of current line
        jsr     add_line_ptr_offset
        stax    line_ptr
        rts

; Adds A to line_ptr.
; Returns result in AX.
; Y SAFE, BC SAFE, DE SAFE

add_line_ptr_offset:
        clc
        adc     line_ptr                ; Add line length to low byte of line_ptr
        ldx     line_ptr+1              ; High byte into X
        bcc     @no_carry               ; Don't need to add the carry to X
        inx                             ; Add the carry to X
@no_carry:
        rts

; Updates the program based on the information in line_buffer.
; If the line number in line_buffer is in the program, remove it.
; If line_buffer contains a new line, then insert it into the program.

insert_or_update_line:
        ldax    line_buffer+Line::number    ; Load line number into AX
        jsr     find_line               ; Go find it
        bcs     @insert                 ; Not found, just insert the new line

; line_ptr points to a line that we have to remove.
; Find the next line and copy the reset of the program to where line_ptr is pointing now.
; There will always be a next line becasue we'll only be here if the line to delete
; actually exists.

        lda     line_ptr                ; Current line_ptr
        sta     dst_ptr                 ; will be the target of the memcpy
        pha                             ; Also push it on the stack so we can restore after advancing
        lda     line_ptr+1              ; High byte
        sta     dst_ptr+1   
        pha 
        jsr     advance_line_ptr        ; Move to line_ptr to next line (AX = line_ptr)
        stax    src_ptr                 ; This will be the source for the copy
        jsr     calculate_bytes_to_move ; Set DE to length of program from line_ptr
        jsr     update_pointers         ; Knowing copy from and to, we can update pointers
        jsr     copy_bytes_de           ; Compact the program
        pla                             ; line_ptr now points to an invalid line so restore saved value
        sta     line_ptr+1
        pla
        sta     line_ptr

; Insert the new line, if there is one.
; There is a line if next_line_offset is greater than the offset of the data field.
; line_ptr points to where this new line should go.

@insert:
        mvax    line_ptr, src_ptr       ; Initialize src_ptr to line_ptr
        lda     line_buffer+Line::next_line_offset  ; Load length of line which should be <= 255
        cmp     #Line::data             ; Compare next line offset with the offset of the data field
        beq     @finish                 ; If they're the same, line is blank, nothing to insert
        jsr     add_line_ptr_offset     ; Add next_line_offset to line_ptr to get new address of current line
        stax    dst_ptr                 ; Store in dst_ptr
        jsr     calculate_bytes_to_move ; Set DE to length of program from line_ptr
        jsr     update_pointers
        jsr     copy_bytes_back_de      ; Make room for the new line
        mvaa    #line_buffer, src_ptr   ; Set up copy into the space for the new line
        mvaa    line_ptr, dst_ptr
        lda     line_buffer+Line::next_line_offset  ; Length of the new line
        ldx     #0                      ; High byte of length is always 0
        jsr     copy_bytes              ; Copy the line into the program

@finish:
        clc
        rts

; Calculates the bytes to move for both compact and expand as (value_table_ptr - line_ptr).
; Returns the number of bytes in DE.

calculate_bytes_to_move:
        sec                       
        lda     value_table_ptr
        sbc     line_ptr
        sta     D                       ; Store low byte of length in D
        lda     value_table_ptr+1      
        sbc     line_ptr+1      
        sta     E                       ; High byte of length in E
        rts

; Updates variable_name_table_ptr and value_table_ptr by adding (dst_ptr - src_ptr).
; In other words, if we're moving everything to a higher address (dst_ptr > src_ptr), then we have
; to move the pointers up too, and vice versa. We're just shifting the pointers by however many bytes
; we moved the end of the program.
; Uses XY to store the difference value.
; BC SAFE, DE SAFE

update_pointers:
        sec           
        lda     dst_ptr
        sbc     src_ptr
        tax                             ; Difference low byte in X
        lda     dst_ptr+1       
        sbc     src_ptr+1     
        tay                             ; Difference high byte in Y
        clc                             ; Update variable_name_table_ptr
        txa                             
        adc     variable_name_table_ptr
        sta     variable_name_table_ptr
        tya
        adc     variable_name_table_ptr+1
        sta     variable_name_table_ptr+1
        clc                             ; Update value_table_ptr
        txa                      
        adc     value_table_ptr
        sta     value_table_ptr
        tya
        adc     value_table_ptr+1
        sta     value_table_ptr+1
        rts

; Tries to grow the variable name table by increasing value_table_ptr by an amount.
; A = the value to add to value_table_ptr
; Returns carry clear if the increase was successful, otherwise carry set.
; BC SAFE, DE SAFE

grow_variable_name_table:
        clc
        adc     value_table_ptr
        tax                             ; Save low byte in X
        lda     #0                      ; Prepare to add high byte
        adc     value_table_ptr+1       ; New himem_ptr is in XA
        bcs     @done                   ; Pointer wrapped around
        tay                             ; Save high byte in Y; new value_table_ptr is in XY
        jsr     check_himem             ; See if new value_table_ptr > himem_ptr
        bcs     @done                   ; check_himem failed so don't update value_table_ptr
        stx     value_table_ptr         ; Validation successful; copy XY into value_table_ptr
        sty     value_table_ptr+1
@done:
        rts

; Checks if a pointer is > himem_ptr.
; Returns carry clear if the pointer is <=himem_ptr, carry set if it is greater.
; XA = the pointer to test (NOTE A IS HIGH BYTE AND X IS LOW BYTE)
; X SAFE, Y SAFE, BC SAFE, DE SAFE

check_himem:
        cmp     himem_ptr+1
        bcc     @done                   ; argument high byte < himem_ptr high byte
        bne     @done                   ; argument high byte > himem_ptr high byte (carry is set)
        txa                             ; High bytes are equal; compare low bytes
        cmp     himem_ptr
        bcc     @done                   ; argument low byte < himem_ptr low byte
        bne     @done                   ; argument low byte > himem_ptr low byte (carry is set)
        clc                             ; Pointers are equal; clear carry since this is success
@done:
        rts

; Calculates the offset of a variable in the value table and sets variable_value_ptr to point to it.
; The variable token passed in A will always be <= 127 since there can only be 128 variables, but it possibly
; has the high bit set, so we AND with $7F first.
; A = the variable token

set_variable_value_ptr:
        and     #$7F                    ; Clear MSB
        jsr     mul2a                   ; Multiply by 2; since MSB was clear, this will clear carry
        adc     value_table_ptr         ; Add to the value table offset
        sta     variable_value_ptr      ; Store low byte
        txa                             
        adc     value_table_ptr+1
        sta     variable_value_ptr+1
        rts

; Sets the value of the variable referenced by variable_value_ptr to the value passed in AX.

set_variable_value:
        ldy     #0                      ; Index variable value with Y
        sta     (variable_value_ptr),y  ; Low byte
        iny
        txa
        sta     (variable_value_ptr),y  ; High byte
        rts
